(function() {
  // Look for modal/expanded content with the prompt text
  const modals = document.querySelectorAll("[role=dialog], .modal, [class*=modal], [class*=overlay], [class*=popup]");
  const pres = document.querySelectorAll("pre");
  const textareas = document.querySelectorAll("textarea");

  // Check for any newly visible large text blocks
  const allDivs = Array.from(document.querySelectorAll("div")).filter(d => {
    const style = window.getComputedStyle(d);
    return style.display !== "none" && d.textContent.length > 500 && d.children.length < 5;
  });

  return JSON.stringify({
    modals: modals.length,
    pres: pres.length,
    textareas: textareas.length,
    largeDivs: allDivs.length,
    firstLargeDiv: allDivs.length > 0 ? allDivs[0].textContent.slice(0, 300) : "none"
  });
})()
